import React, { useState } from 'react'
import { useReviewsContext, ReviewsProvider } from './ReviewsProvider'
import './styles.css'
import { FaRegStar, FaStar } from "react-icons/fa6";


export function ReviewRating({ rating = 0, readOnly, onSelectRating }) {
    const [currRating, setCurrRating] = useState(rating)
    const starsCount = [1, 2, 3, 4, 5]
    function handleStar(starValue) {
        setCurrRating(starValue)
        onSelectRating(starValue)
    }
    return (
        <div className='star-rating'>{starsCount.map((star) => {
            return star <= currRating ? <FaStar style={{ color: '#E5B30B' }} onClick={() => !readOnly && handleStar(star)} /> : <FaRegStar onClick={() => !readOnly && handleStar(star)} />
        })}</div>
    )
}

export function ReviewForm() {
    const { saveForm } = useReviewsContext()
    const [formValues, setFormValues] = useState({
        reviewText: '',
        title: '',
        rating: 0
    })
    const [error, setError] = useState({
        reviewText: null,
        title: null,
        rating: null
    })
    const [hasError, setHasError] = useState(false)
    const [success, setSuccess] = useState(null)

    function handleTitle(e) {
        setFormValues((prev) => {
            return { ...prev, title: e.target.value }
        })
    }
    function handleReviewText(e) {
        setFormValues((prev) => {
            return { ...prev, reviewText: e.target.value }
        })
    }
    function handleRating(stars) {
        setFormValues((prev) => {
            return { ...prev, rating: stars }
        })
    }
    function handleSubmit() {
        const { reviewText, rating, title } = formValues
        if (reviewText.length === 0) {
            setError((prev) => {
                return { ...error, reviewText: 'Review text is empty!' }
            })
            setHasError(true)
        }
        else if (title.length === 0) {
            setError((prev) => {
                return { ...error, title: 'Title is empty!' }
            })
            setHasError(true)
        }
        else if (rating === 0) {
            setError((prev) => {
                return { ...error, rating: 'Please give us a rating!' }
            })
            setHasError(true)
        } else {
            saveForm({ ...formValues })
            setSuccess('Review submitted successfully!')
        }

    }
    const showSubmitStatus = () => {
        if (hasError) {
            return <div>{
                Object.values(error).map(err => {
                    return (
                        <span style={{ color: 'red' }}>{err}</span>
                    )
                })
            }</div>
        } else if (success) {
            <span style={{ color: 'green' }}>{success}</span>
        }
    }
    const TitleInput = () => <input value={formValues.title} id="title" type='text' placeholder='Title...' onChange={handleTitle} />
    const ReviewTextInput = () => <input value={formValues.reviewText} type='text' placeholder='Please write your review...' onChange={handleReviewText} />
    return (
        <div className='form-container'>
            <input value={formValues.title} id="title" type='text' placeholder='Title...' onChange={handleTitle} />
            <div className='form-element'>
                <label >Title:</label>
                <TitleInput />
            </div >
            <div className='form-element'>
                <label >{`${labeValue}:`}</label>
                <TitleInput />
            </div >
            <div className='form-element'>
                <label >{`${labeValue}:`}</label>
                <TitleInput />
            </div >
            <ReviewFormElement labeValue={'Title'} formElement={<TitleInput />} htmlFor={'title'} />
            <ReviewFormElement labeValue={'Review'} formElement={<ReviewTextInput />} />
            <ReviewFormElement labeValue={'Rating'} formElement={<ReviewRating onSelectRating={handleRating} />} />
            <button onClick={handleSubmit} className='submit-review-button'>Submit Review!</button>
            {showSubmitStatus()}
        </div>
    )
}

export function ReviewTitle({ title }) {
    return (
        <div>{title}</div>
    )
}

export function ReviewText({ reviewText }) {
    return (
        <div>{reviewText}</div>
    )
}

export function Reviews() {
    const { reviews } = useReviewsContext()
    if (reviews.length > 0) {
        return (
            <ul>
                {reviews.map(({ title, reviewText, rating }) => <li>
                    <ReviewTitle title={title} />
                    <ReviewText reviewText={reviewText} />
                    <ReviewRating readOnly={true} rating={rating} />
                </li>)}
            </ul>
        )
    }
}
function ReviewsRating() {
    return <>
        <ReviewsProvider>
            <div style={{ display: 'flex', flexDirection: 'column' }}>
                <ReviewForm />
                <Reviews />
            </div>
        </ReviewsProvider>
    </>
}

export default ReviewsRating
